Add a test that registers a channel with a controllable onMessage trigger, calls the trigger, and asserts the global handler receives the message. For example:

it('should forward channel messages to global handler', () => {
  const registry = new ChannelRegistry()
  const wa = createStubChannel('whatsapp')
  // Capture the onMessage handler registered by the registry
  let registryHandler: MessageHandler | null = null
  const originalOnMessage = wa.onMessage
  wa.onMessage = (handler) => { registryHandler = handler; return originalOnMessage(handler) }
  registry.register(wa, config)
  const received: IncomingMessage[] = []
  registry.onAnyMessage((msg) => received.push(msg))
  // Trigger through the captured handler
  registryHandler!({ id: '1', platform: 'whatsapp', ... })
  expect(received).toHaveLength(1)
})

