Add a parallel test:

it('should isolate disconnect faults - one channel error should not affect others', async () => {
  const registry = new ChannelRegistry()
  const failingChannel = createStubChannel('whatsapp', {
    async disconnect() { throw new Error('disconnect failed') },
  })
  const workingChannel = createStubChannel('slack')
  registry.register(failingChannel, waConfig)
  registry.register(workingChannel, slackConfig)
  await registry.connectAll()
  const results = await registry.disconnectAll()
  expect(results.get('whatsapp')?.success).toBe(false)
  expect(results.get('slack')?.success).toBe(true)
  expect(workingChannel.status).toBe('disconnected')
})

Add a test with extendedTextMessage format:

it('should extract text from extendedTextMessage', async () => {
  const mockSocket = createMockBaileysSocket()
  const channel = new WhatsAppChannel(config, { createSocket: () => mockSocket })
  await channel.connect()
  const received: Array<{ text: string }> = []
  channel.onMessage((msg) => received.push({ text: msg.text }))
  mockSocket._emit('messages.upsert', {
    messages: [{
      key: { remoteJid: '123@s.whatsapp.net', fromMe: false, id: 'msg-ext' },
      message: { extendedTextMessage: { text: 'Quoted reply text' } },
      messageTimestamp: Math.floor(Date.now() / 1000),
    }],
    type: 'notify',
  })
  expect(received[0].text).toBe('Quoted reply text')
})

